fn main(){ let n=1000000i64; let mut a=vec![0i64;n as usize]; for i in 0..n as usize { a[i]=i as i64*2; } let mut found=0i64; let mut q=0i64; while q<10000000 { let key=(q*7)%(n*2); let mut lo=0i64; let mut hi=n-1; while lo<=hi { let mid=(lo+hi)/2; if a[mid as usize]==key { found+=1; lo=hi+1; } else if a[mid as usize]<key { lo=mid+1; } else { hi=mid-1; } } q+=1; } println!("{}",found); }
